using System;
using System.Drawing;
using System.IO;
using System.Windows.Forms;

namespace PotirendabaApp.Services
{
    /// <summary>
    /// Brasão da Prefeitura de Potirendaba embutido em Base64.
    /// Duas versões: grande (160px) para o centro, pequena (36px) para a topBar.
    /// </summary>
    public static class LogoHelper
    {
        // Versão grande 160×160px — centro da MainForm
        private const string LogoGrandeBase64 =
            "";

        // Versão pequena 36×36px — topBar (mais leve, carrega mais rápido)
        private const string LogoPequenoBase64 =
            "";

        private static Image _cacheGrande  = null;
        private static Image _cachePequeno = null;

        public static Image GetLogo(bool pequeno = false)
        {
            if (pequeno)
            {
                if (_cachePequeno != null) return _cachePequeno;
                try
                {
                    byte[] b = Convert.FromBase64String(LogoPequenoBase64);
                    _cachePequeno = Image.FromStream(new MemoryStream(b));
                }
                catch { _cachePequeno = null; }
                return _cachePequeno;
            }
            else
            {
                if (_cacheGrande != null) return _cacheGrande;
                try
                {
                    byte[] b = Convert.FromBase64String(LogoGrandeBase64);
                    _cacheGrande = Image.FromStream(new MemoryStream(b));
                }
                catch { _cacheGrande = null; }
                return _cacheGrande;
            }
        }

        /// <summary>PictureBox para uso nas barras verdes das telas internas.</summary>
        public static PictureBox CriarPictureBox(int x = 6, int y = 3, int tamanho = 44, int alturaBar = 54)
        {
            int centroY = (alturaBar - tamanho) / 2;
            return new PictureBox
            {
                Image     = GetLogo(pequeno: true),
                SizeMode  = PictureBoxSizeMode.Zoom,
                Location  = new Point(x, centroY > 0 ? centroY : y),
                Size      = new Size(tamanho, tamanho),
                BackColor = Color.Transparent
            };
        }

        // Versão 32×32px para ícone da janela (barra de título)
        private const string LogoIconBase64 =
            "";

        private static Icon _cacheIcon = null;

        /// <summary>
        /// Retorna o brasão como Icon para usar em Form.Icon.
        /// Converte PNG 32×32 → Icon em memória.
        /// </summary>
        public static Icon GetIcon()
        {
            if (_cacheIcon != null) return _cacheIcon;
            try
            {
                byte[] bytes  = Convert.FromBase64String(LogoIconBase64);
                var bitmap    = new System.Drawing.Bitmap(new MemoryStream(bytes));
                var iconHandle = bitmap.GetHicon();
                _cacheIcon    = Icon.FromHandle(iconHandle);
            }
            catch { _cacheIcon = null; }
            return _cacheIcon;
        }
    }
}
